        univ_calif_pubs.add(pub_num)
    else:
        match2 = re.search(r'publication number\s+([A-Z]{2}-[^,\s]+)', patents_info, re.IGNORECASE)
        if match2:
            pub_num = match2.group(1)
            univ_calif_pubs.add(pub_num)

result = {
