                        cpc_list = json.loads(rec['cpc'])
                        cpc_codes = [item['code'] for item in cpc_list]
                    except:
                        pass

                citing_data.append({
                    'assignee': assignee,
                    'cpc_codes': cpc_codes
                })
                break
    except:
        pass

