# Store results for next step
result = {
    'assignee_data': {k: {
        'citation_count': v['citation_count'],
        'cpc_codes': list(v['cpc_codes'])
    } for k, v in assignee_data.items()},
    'all_cpc_codes': list(all_primary_cpc)
}

print('\\n__RESULT__:')
